import React from 'react';
import { motion } from 'framer-motion';
import { useInView } from 'react-intersection-observer';
import './Skills.css';

const Skills = () => {
  const [ref, inView] = useInView({
    triggerOnce: true,
    threshold: 0.1
  });

  const skillCategories = [
    {
      title: 'Programming Languages',
      skills: ['Python', 'Java', 'C++', 'C', 'JavaScript']
    },
    {
      title: 'Web Technologies',
      skills: ['HTML/CSS', 'React', 'Node.js', 'Next.js', 'Express']
    },
    {
      title: 'Database',
      skills: ['MySQL', 'MongoDB', 'PostgreSQL']
    },
    {
      title: 'Tools & Frameworks',
      skills: ['Git', 'n8n', 'REST APIs', 'UI/UX Design']
    },
    {
      title: 'Core Competencies',
      skills: ['Data Structures', 'Algorithms', 'Machine Learning', 'Problem Solving']
    }
  ];

  return (
    <section className="skills" id="skills">
      <div className="container">
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 50 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
        >
          <h2 className="section-title">Technical Skills</h2>

          <div className="skills-grid">
            {skillCategories.map((category, catIndex) => (
              <motion.div
                key={catIndex}
                className="skill-category"
                initial={{ opacity: 0, y: 30 }}
                animate={inView ? { opacity: 1, y: 0 } : {}}
                transition={{ delay: catIndex * 0.15, duration: 0.5 }}
              >
                <h3 className="category-title">{category.title}</h3>
                <div className="skills-tags">
                  {category.skills.map((skill, skillIndex) => (
                    <motion.span
                      key={skillIndex}
                      className="skill-tag"
                      initial={{ opacity: 0, scale: 0.8 }}
                      animate={inView ? { opacity: 1, scale: 1 } : {}}
                      transition={{ delay: catIndex * 0.15 + skillIndex * 0.05, duration: 0.3 }}
                      whileHover={{ scale: 1.05, y: -3 }}
                    >
                      {skill}
                    </motion.span>
                  ))}
                </div>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </div>
    </section>
  );
};

export default Skills;
